-- STEP 1: query [kommuner]
SELECT kommunenummer FROM kommuner.kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%Trondheim%' LIMIT 1;

-- STEP BOUNDARY --

-- STEP 2: query [matrikkelenbygning]
SELECT objid, representasjonspunkt FROM matrikkelenbygning.matrikkelenbygning_e58ed5b5abd74bc1a42ff55d569f0cf4.bygning WHERE kommunenummer = '5001';

-- STEP BOUNDARY --

-- STEP 3: query [kvikkleire]
SELECT objid, omrade FROM kvikkleire.kvikkleire_87067f98e29a47d4901328f3a926a515.utlopomr WHERE ST_Intersects(omrade, (SELECT omrade FROM kommuner.kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenummer = '5001'));

